import{_ as a,c as s,o as i,ak as t,an as o}from"./chunks/framework.B0TWM2iJ.js";const p=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v2-44-0.md","filePath":"aireblock-releases/aireframe-v2-44-0.md","lastUpdated":1776845066000}'),r={name:"aireblock-releases/aireframe-v2-44-0.md"};function n(l,e,c,d,m,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.44.0<br><strong>Release Date:</strong> February 23, 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="🚨-critical-fixes" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h4><ul><li>Forms Now Stay Within AireFrame on Mobile Devices (FRAME-2475)</li></ul><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Subject Banner Auto-Refresh (FRAME-2375)</li><li>Reliable Form Submission (FRAME-2437)</li><li>Configurable AI Prompts (FRAME-2388)</li><li>Improved AI Data Processing (FRAME-2441)</li><li>Dashboard Dependency Tracking (FRAME-2401)</li><li>Better Loading Indicators (FRAME-2405)</li><li>Consistent Theme Support (FRAME-2427)</li><li>Built-In Status Page Access (FRAME-2451)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Faster Data Visualisations (FRAME-2336)</li><li>Faster Subject Lists (FRAME-2470)</li><li>Reduced CPU Usage (FRAME-2465)</li><li>Improved Widget Full Screen (FRAME-2460)</li><li>Enhanced Subject List v2 (FRAME-2265)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Keyboard Navigation in Forms (FRAME-2466)</li><li>Reliable GraphQL WebSocket Connections (FRAME-2327)</li></ul><h3 id="⚠️-upgrade-notes" tabindex="-1">⚠️ Upgrade Notes <a class="header-anchor" href="#⚠️-upgrade-notes" aria-label="Permalink to “⚠️ Upgrade Notes”">​</a></h3><hr><div class="warning custom-block"><p class="custom-block-title">Subject List Migration</p><p>If you&#39;re using the legacy subject list section, plan to migrate your dashboards. The subject list section is now delete-only, and empty sections will be hidden automatically. See migration guide for details.</p></div><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="🚨-critical-fixes-1" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes-1" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h3><hr><h4 id="forms-now-stay-within-aireframe-on-mobile-devices-frame-2475" tabindex="-1">Forms Now Stay Within AireFrame on Mobile Devices (FRAME-2475) <a class="header-anchor" href="#forms-now-stay-within-aireframe-on-mobile-devices-frame-2475" aria-label="Permalink to “Forms Now Stay Within AireFrame on Mobile Devices (FRAME-2475)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Forms now remain inline within AireFrame when accessed on mobile devices or with browser zoom at 200%. The subject banner stays visible at all times during form completion, eliminating the risk where staff could complete a form for the wrong subject.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Fixed issue where forms opened in separate browser tabs on mobile or at 200% zoom, which removed subject context and bypassed session timeout mechanisms. Forms now render inline with proper session management and subject banner visibility maintained across all contexts.</p></div><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="subject-banner-auto-refresh-frame-2375" tabindex="-1">Subject Banner Auto-Refresh (FRAME-2375) <a class="header-anchor" href="#subject-banner-auto-refresh-frame-2375" aria-label="Permalink to “Subject Banner Auto-Refresh (FRAME-2375)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When subject details are updated, the banner at the top of the screen now automatically refreshes to show the latest information. You no longer need to manually refresh the page to see updated data, ensuring you&#39;re always working with current information.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Subject banner now subscribes to subject detail updates and refreshes automatically to display the most recent data in real-time.</p></div><h4 id="reliable-form-submission-frame-2437" tabindex="-1">Reliable Form Submission (FRAME-2437) <a class="header-anchor" href="#reliable-form-submission-frame-2437" aria-label="Permalink to “Reliable Form Submission (FRAME-2437)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Forms no longer fail to submit due to session timeouts. If you&#39;re working on a lengthy form, the system now maintains your authentication properly, preventing lost work and ensuring forms submit successfully.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Fixed form submission failures caused by AireFrame token timeouts. Implemented proper token refresh mechanism for long-running form sessions.</p></div><h4 id="configurable-ai-prompts-frame-2388" tabindex="-1">Configurable AI Prompts (FRAME-2388) <a class="header-anchor" href="#configurable-ai-prompts-frame-2388" aria-label="Permalink to “Configurable AI Prompts (FRAME-2388)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>AI-generated summaries and insights can now be customised to match your organisation&#39;s specific workflows and terminology. Administrators can configure AI behaviour via templates to produce more relevant and accurate summaries for your use cases.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>AI prompts are now template-driven, allowing tenant-level customisation of AI behaviour and output formatting.</p></div><h4 id="improved-ai-data-processing-frame-2441" tabindex="-1">Improved AI Data Processing (FRAME-2441) <a class="header-anchor" href="#improved-ai-data-processing-frame-2441" aria-label="Permalink to “Improved AI Data Processing (FRAME-2441)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>AI summaries now correctly handle user identifiers and formatted data points, producing more accurate and contextually relevant summaries of your data.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>UserIdentifier and format datapoints are now resolved before being passed to AI summarisation, improving accuracy of AI-generated content.</p></div><h4 id="dashboard-dependency-tracking-frame-2401" tabindex="-1">Dashboard Dependency Tracking (FRAME-2401) <a class="header-anchor" href="#dashboard-dependency-tracking-frame-2401" aria-label="Permalink to “Dashboard Dependency Tracking (FRAME-2401)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now see which widgets and data pipelines are using specific dashboards or data sets, and vice versa. This makes it easier to understand dependencies when making configuration changes, helping you avoid accidentally breaking dashboards used by other parts of your build.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Added &quot;used by&quot; and &quot;uses&quot; columns to widget, pipeline, and data set lists for better dependency visibility.</p></div><h4 id="better-loading-indicators-frame-2405" tabindex="-1">Better Loading Indicators (FRAME-2405) <a class="header-anchor" href="#better-loading-indicators-frame-2405" aria-label="Permalink to “Better Loading Indicators (FRAME-2405)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Widgets now show clear skeleton loaders while data is loading, giving you visual feedback that the system is working rather than appearing frozen. This is especially helpful for widgets displaying large datasets or complex visualisations.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Implemented skeleton loading states for all widget types, replacing generic spinners with contextual loading UI.</p></div><h4 id="consistent-theme-support-frame-2427" tabindex="-1">Consistent Theme Support (FRAME-2427) <a class="header-anchor" href="#consistent-theme-support-frame-2427" aria-label="Permalink to “Consistent Theme Support (FRAME-2427)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>All text and titles throughout AireFrame now properly respect your organisation&#39;s custom theme colours, providing a more consistent branded experience across the entire platform.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Updated title and text rendering components to apply theme colour settings consistently across all UI elements.</p></div><h4 id="built-in-status-page-access-frame-2451" tabindex="-1">Built-In Status Page Access (FRAME-2451) <a class="header-anchor" href="#built-in-status-page-access-frame-2451" aria-label="Permalink to “Built-In Status Page Access (FRAME-2451)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now check the AireInnovate platform status directly from within AireFrame without opening a separate browser tab. This makes it easier to quickly verify if any issues you&#39;re experiencing are due to planned maintenance or system incidents.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Integrated status.aireinnovate.com access within AireFrame interface for direct platform status monitoring.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="faster-data-visualisations-frame-2336" tabindex="-1">Faster Data Visualisations (FRAME-2336) <a class="header-anchor" href="#faster-data-visualisations-frame-2336" aria-label="Permalink to “Faster Data Visualisations (FRAME-2336)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Dashboards and visualisations load significantly faster, especially when viewing the same data multiple times. This is particularly noticeable on dashboards with many widgets or complex data queries.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Added caching layer for visualisation queries, reducing database CPU usage and improving dashboard rendering performance for frequently accessed data.</p></div><h4 id="faster-subject-lists-frame-2470" tabindex="-1">Faster Subject Lists (FRAME-2470) <a class="header-anchor" href="#faster-subject-lists-frame-2470" aria-label="Permalink to “Faster Subject Lists (FRAME-2470)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Subject lists now load quickly, even on first access or after cache is cleared. You no longer need to refresh the page multiple times to see your subject list data.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Fixed performance issue where subject lists required multiple page refreshes when cache data didn&#39;t exist. Improved data subscription handling for subject list views.</p></div><h4 id="reduced-cpu-usage-frame-2465" tabindex="-1">Reduced CPU Usage (FRAME-2465) <a class="header-anchor" href="#reduced-cpu-usage-frame-2465" aria-label="Permalink to “Reduced CPU Usage (FRAME-2465)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>System performance is more stable, especially for organisations with large data structures. You should experience fewer slowdowns and more responsive interfaces across the platform.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Resolved CPU spikes in LocalStore after .NET 10 upgrade. Optimised handling of tenants with large structural hierarchies.</p></div><h4 id="improved-widget-full-screen-frame-2460" tabindex="-1">Improved Widget Full Screen (FRAME-2460) <a class="header-anchor" href="#improved-widget-full-screen-frame-2460" aria-label="Permalink to “Improved Widget Full Screen (FRAME-2460)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When expanding a widget to full screen, it now appears as a modal taking ~80% of the screen with a darkened background, rather than completely taking over your browser. You can press ESC to quickly close it. This makes it easier to reference other information while viewing detailed data.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Converted full-screen widget mode to modal dialogue with 80% viewport coverage, backdrop overlay, and ESC key support for dismissal.</p></div><h4 id="enhanced-subject-list-v2-frame-2265" tabindex="-1">Enhanced Subject List v2 (FRAME-2265) <a class="header-anchor" href="#enhanced-subject-list-v2-frame-2265" aria-label="Permalink to “Enhanced Subject List v2 (FRAME-2265)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Subject list section is now streamlined - existing dashboards can be removed, but new ones cannot be added to the legacy section. If you have no dashboards in the subject list section, it won&#39;t display at all, reducing clutter in your interface.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Subject list section is now delete-only; empty sections are automatically hidden. Migration path provided for transitioning away from legacy subject list configuration.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="keyboard-navigation-in-forms-frame-2466" tabindex="-1">Keyboard Navigation in Forms (FRAME-2466) <a class="header-anchor" href="#keyboard-navigation-in-forms-frame-2466" aria-label="Permalink to “Keyboard Navigation in Forms (FRAME-2466)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed focus trap in overlay components to prevent keyboard focus from escaping when tabbing past the Submit button.</p></div><h4 id="reliable-graphql-websocket-connections-frame-2327" tabindex="-1">Reliable GraphQL WebSocket Connections (FRAME-2327) <a class="header-anchor" href="#reliable-graphql-websocket-connections-frame-2327" aria-label="Permalink to “Reliable GraphQL WebSocket Connections (FRAME-2327)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed BFF GraphQL WebSocket errors occurring during API upgrades. Improved connection state management and error handling during deployment processes.</p></div>',70)])])}const b=a(r,[["render",n]]);export{p as __pageData,b as default};
